on? // Habilidades típicas (ex: [\"Forja\", \"Magia de Fogo\"])\n  requirements  String?     @db.Text // Requisitos para a profissão\n  isTemplate    Boolean     @default(false)\n  characters    Character[]\n  createdAt     DateTime    @default(now())\n  updatedAt     DateTime    @updatedAt\n}\n\nmodel Kingdom {\n  id             String  @id @default(uuid())\n  worldId        String\n  world          World   @relation(fields: [worldId], references: [id], onDelete: Cascade)\n  name           String\n  description    String? @db.Text\n  governmentType String?\n\n  // LIGAÇÃO 1: O Governante\n  rulerCharacterId String?    @unique\n  rulerCharacter   Character? @relation(\"KingdomRuler\", fields: [rulerCharacterId], references: [id])\n\n  // LIGAÇÃO 2: Os Cidadãos\n  characters Character[] @relation(\"KingdomCitizens\")\n\n  createdAt DateTime @default(now())\n}\n\nmodel Location {\n  id               String     @id @default(uuid())\n  worldId          String\n  world            World      @relation(fields: [worldId], references: [id], onDelete: Cascade)\n  parentLocationId String? // Para hierarquia: Continente -> País -> Cidade\n  parentLocation   Location?  @relation(\"LocationHierarchy\", fields: [parentLocationId], references: [id])\n  childLocations   Location[] @relation(\"LocationHierarchy\")\n  name             String\n  type             String // ex: \"Continente\", \"Cidade\", \"Floresta\"\n  description      String?    @db.Text\n  coordinates      String? // ex: \"N 45°, E 12°\" ou texto livre\n  events           Event[]\n  createdAt        DateTime   @default(now())\n}\n\n// ==========================================\n// 3. LINHA DO TEMPO E EVENTOS\n// ==========================================\n\nmodel Timeline {\n  id          String   @id @default(uuid())\n  worldId     String\n  world       World    @relation(fields: [worldId], references: [id], onDelete: Cascade)\n  name        String // ex: \"Terceira Era\", \"Calendário Imperial\"\n  description String?  @db.Text\n  isPrimary   Boolean  @default(false) // A linha do tempo principal do mundo\n  events      Event[]\n  createdAt   DateTime @default(now())\n}\n\nmodel Event {\n  id         String    @id @default(uuid())\n  worldId    String\n  world      World     @relation(fields: [worldId], references: [id], onDelete: Cascade)\n  timelineId String?\n  timeline   Timeline? @relation(fields: [timelineId], references: [id])\n  locationId String?\n  location   Location? @relation(fields: [locationId], references: [id])\n\n  name        String\n  description String? @db.Text\n\n  // Campos para ordenação cronológica real\n  year      Int? // ex: 305\n  month     Int? // ex: 7 (opcional)\n  day       Int? // ex: 12 (opcional)\n  sortOrder Int  @default(0) // Fallback para ordenar eventos sem data exata\n\n  // Campo para exibição flexível (ex: \"No ano da Grande Queda\")\n  displayDate String?\n\n  characters CharacterEvent[]\n  createdAt  DateTime         @default(now())\n}\n\n// ==========================================\n// 4. PERSONAGENS\n// ==========================================\n\nmodel Character {\n  id      String @id @default(uuid())\n  worldId String\n  world   World  @relation(fields: [worldId], references: [id], onDelete: Cascade)\n\n  raceId String?\n  race   Race?   @relation(fields: [raceId], references: [id])\n\n  professionId String?\n  profession   Profession? @relation(fields: [professionId], references: [id])\n\n  skills Json? // NOVO: Ex: [\"Bola de Fogo Nível 3\", \"Furtividade\"]\n\n  // LIGAÇÃO 2: O Reino a que o personagem pertence (Cidadão)\n  kingdomId String?\n  kingdom   Kingdom? @relation(\"KingdomCitizens\", fields: [kingdomId], references: [id])\n\n  name        String\n  alias       String?\n  description String? @db.Text\n  age         String?\n  alignment   String?\n\n  birthYear Int?\n  deathYear Int?\n  isAlive   Boolean @default(true)\n\n  events CharacterEvent[]\n\n  // LIGAÇÃO 1: O Reino que o personagem governa (Governante)\n  ruledKingdom Kingdom? @relation(\"KingdomRuler\")\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel Concept {\n  id          String   @id @default(uuid())\n  worldId     String\n  world       World    @relation(fields: [worldId], references: [id], onDelete: Cascade)\n  name        String // Ex: \"A Teia Mágica\", \"O Pacto de Sangue\"\n  description String   @db.Text\n  createdAt   DateTime @default(now())\n}\n\n// Adiciona isto ao teu schema.prisma (antes do CharacterEvent)\n\nmodel LoreEntry {\n  id      String @id @default(uuid())\n  worldId String\n  world   World  @relation(fields: [worldId], references: [id], onDelete: Cascade)\n\n  category    String // Ex: \"DEITY\", \"SPELL\", \"ITEM\", \"LAW\", \"CUSTOM\", \"AFTERMATH\"\n  name        String\n  description String @db.Text // Texto rico para a lore profunda\n\n  // A MÁGICA DA ORGANIZAÇÃO FLEXÍVEL\n  customData Json? // Dados específicos (ex: {\"dano\": \"2d6\"} ou {\"populacao_afetada\": \"30%\"})\n  tags       String[] // Ex: [\"Fogo\", \"Proibido\", \"Élfico\"]\n  relatedIds String[] // IDs de outros entries, personagens ou locais relacionados\n\n  // RESOLVENDO A QUESTÃO DA ESCALA\n  scale String @default(\"LOCAL\") // \"VILLAGE\", \"CITY\", \"REGION\", \"CONTINENT\", \"PLANETARY\"\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// Tabela de junção para relação N:N entre Personagens e Eventos\nmodel CharacterEvent {\n  characterId String\n  character   Character @relation(fields: [characterId], references: [id], onDelete: Cascade)\n  eventId     String\n  event       Event     @relation(fields: [eventId], references: [id], onDelete: Cascade)\n  roleInEvent String? // ex: \"Protagonista\", \"Vítima\", \"Observador\"\n\n  @@id([characterId, eventId])\n}\n",
  "inlineSchemaHash": "ee2e9f3a06d280350237e536a1aca345352d6fb2da0ddebacbcee779ac457374",
